/// READ FLATFILE
fn flatfile_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_flatfile.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(28);
            if _len > 0 { let _end = _len.min(0+2); let _s = String::from_utf8_lossy(&_bytes[0.._end]).trim().to_string(); state.seq = _s.parse().unwrap_or_default(); }
            if _len > 2 { let _end = _len.min(2+2); let _s = String::from_utf8_lossy(&_bytes[2.._end]).trim().to_string(); state.dep_x = _s.parse().unwrap_or_default(); }
            if _len > 4 { let _end = _len.min(4+2); let _s = String::from_utf8_lossy(&_bytes[4.._end]).trim().to_string(); state.dep_y = _s.parse().unwrap_or_default(); }
            if _len > 6 { let _end = _len.min(6+5); state.hello = FixedString::from(String::from_utf8_lossy(&_bytes[6.._end])); }
            if _len > 11 { let _end = _len.min(11+2); state.tstx = FixedString::from(String::from_utf8_lossy(&_bytes[11.._end])); }
            if _len > 11 { let _end = _len.min(11+2); state.tstg_1 = FixedString::from(String::from_utf8_lossy(&_bytes[11.._end])); }
            if _len > 13 { let _end = _len.min(13+4); state.tsttail1 = FixedString::from(String::from_utf8_lossy(&_bytes[13.._end])); }
            if _len > 17 { let _end = _len.min(17+9); state.tsty = FixedString::from(String::from_utf8_lossy(&_bytes[17.._end])); }
            if _len > 17 { let _end = _len.min(17+2); let _s = String::from_utf8_lossy(&_bytes[17.._end]).trim().to_string(); state.tsty_1 = _s.parse().unwrap_or_default(); }
            if _len > 19 { let _end = _len.min(19+3); state.tsty_2 = FixedString::from(String::from_utf8_lossy(&_bytes[19.._end])); }
            for _i in 0..1 {
                let _off = 22 + _i * 1;
                if _len > _off { let _end = _len.min(_off+1); state.tsty_3[_i] = FixedString::from(String::from_utf8_lossy(&_bytes[_off.._end])); }
            }
            if _len > 23 { let _end = _len.min(23+2); state.tsty_4 = FixedString::from(String::from_utf8_lossy(&_bytes[23.._end])); }
            if _len > 25 { let _end = _len.min(25+1); state.tsty_5 = FixedString::from(String::from_utf8_lossy(&_bytes[25.._end])); }
            if _len > 25 { let _end = _len.min(25+1); state.tsty_6 = FixedString::from(String::from_utf8_lossy(&_bytes[25.._end])); }
            if _len > 25 { let _end = _len.min(25+1); state.tsty_7 = FixedString::from(String::from_utf8_lossy(&_bytes[25.._end])); }
            if _len > 26 { let _end = _len.min(26+2); state.tsttail2 = FixedString::from(String::from_utf8_lossy(&_bytes[26.._end])); }
            state._fs_flatfile = FileStatus::Success;
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
        Err(FileStatus::AtEnd) => {
            state._fs_flatfile = FileStatus::AtEnd;
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
        Err(e) => {
            state._fs_flatfile = e.clone();
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
    }
    Ok(())
}

/// WRITE to FLATFILE
fn flatfile_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 28];
    { let _s = format!("{:>width$}", state.seq, width = 2); let _b = _s.as_bytes(); let _cl = _b.len().min(2); _buf[0..0+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _s = format!("{:>width$}", state.dep_x, width = 2); let _b = _s.as_bytes(); let _cl = _b.len().min(2); _buf[2..2+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _s = format!("{:>width$}", state.dep_y, width = 2); let _b = _s.as_bytes(); let _cl = _b.len().min(2); _buf[4..4+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.hello.as_bytes(); let _end = (6+5).min(_buf.len()); let _cl = _src.len().min(_end-6); _buf[6..6+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tstg_1.as_bytes(); let _end = (11+2).min(_buf.len()); let _cl = _src.len().min(_end-11); _buf[11..11+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tsttail1.as_bytes(); let _end = (13+4).min(_buf.len()); let _cl = _src.len().min(_end-13); _buf[13..13+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.tsty_1, width = 2); let _b = _s.as_bytes(); let _cl = _b.len().min(2); _buf[17..17+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.tsty_2.as_bytes(); let _end = (19+3).min(_buf.len()); let _cl = _src.len().min(_end-19); _buf[19..19+_cl].copy_from_slice(&_src[.._cl]); }
    for _i in 0..1 {
        let _off = 22 + _i * 1;
        { let _src = state.tsty_3[_i].as_bytes(); let _end = (_off+1).min(_buf.len()); let _cl = _src.len().min(_end-_off); _buf[_off.._off+_cl].copy_from_slice(&_src[.._cl]); }
    }
    { let _src = state.tsty_4.as_bytes(); let _end = (23+2).min(_buf.len()); let _cl = _src.len().min(_end-23); _buf[23..23+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tsty_7.as_bytes(); let _end = (25+1).min(_buf.len()); let _cl = _src.len().min(_end-25); _buf[25..25+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.tsttail2.as_bytes(); let _end = (26+2).min(_buf.len()); let _cl = _src.len().min(_end-26); _buf[26..26+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_flatfile.write_record(&_buf) {
        Ok(()) => state._fs_flatfile = FileStatus::Success,
        Err(e) => state._fs_flatfile = e,
    }
}

/// CLOSE FLATFILE
fn flatfile_close(state: &mut ProgramState) {
    match state._fh_flatfile.close() {
        Ok(()) => state._fs_flatfile = FileStatus::Success,
        Err(e) => state._fs_flatfile = e,
    }
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
}

